import { describe, it, expect, vi, beforeEach } from 'vitest'
import { render, screen } from '@testing-library/react'
import { MantineProvider } from '@mantine/core'
import { InstitutionDetail } from './InstitutionDetail'

const { mockUseQuery } = vi.hoisted(() => ({ mockUseQuery: vi.fn() }))
vi.mock('urql', () => ({ useQuery: mockUseQuery }))

// Mock useMediaQuery to return false (desktop) by default
vi.mock('@mantine/hooks', async () => {
  const actual = await vi.importActual<typeof import('@mantine/hooks')>('@mantine/hooks')
  return { ...actual, useMediaQuery: () => false }
})

const MOCK_INSTITUTION = {
  unitID: '166683',
  name: 'MIT',
  city: 'Cambridge',
  state: 'MA',
  latitude: 42.36,
  longitude: -71.09,
  institutionType: '2',
  enrollment: 11574,
  graduationRate: 0.94,
  admissionRate: 0.04,
  inStateTuition: 57590,
  outOfStateTuition: 57590,
  avgNetPrice: 21642,
  retentionRate: 0.99,
  studentFacultyRatio: 3,
}

function renderDetail(props: Partial<Parameters<typeof InstitutionDetail>[0]> = {}) {
  return render(
    <MantineProvider>
      <InstitutionDetail
        unitID="166683"
        opened={true}
        onClose={vi.fn()}
        {...props}
      />
    </MantineProvider>,
  )
}

describe('InstitutionDetail', () => {
  beforeEach(() => {
    mockUseQuery.mockReset()
  })

  it('shows a loader while fetching', () => {
    mockUseQuery.mockReturnValue([{ fetching: true, data: undefined, error: undefined }, vi.fn()])
    renderDetail()
    expect(screen.getByRole('dialog')).toBeInTheDocument()
    const dialog = screen.getByRole('dialog')
    expect(dialog.querySelector('.mantine-Loader-root')).toBeInTheDocument()
  })

  it('shows an error message on query failure', () => {
    mockUseQuery.mockReturnValue([
      { fetching: false, data: undefined, error: new Error('network') },
      vi.fn(),
    ])
    renderDetail()
    expect(screen.getByText(/failed to load institution details/i)).toBeInTheDocument()
  })

  it('renders institution details when data is loaded', () => {
    mockUseQuery.mockReturnValue([
      { fetching: false, data: { institution: MOCK_INSTITUTION }, error: undefined },
      vi.fn(),
    ])
    renderDetail()
    // MIT appears in both modal title and body
    expect(screen.getAllByText('MIT').length).toBeGreaterThanOrEqual(1)
    expect(screen.getByText('Cambridge, MA')).toBeInTheDocument()
    expect(screen.getByText('Private nonprofit')).toBeInTheDocument()
    expect(screen.getByText('11,574')).toBeInTheDocument()
    expect(screen.getByText('3:1')).toBeInTheDocument()
    // In-state and out-of-state tuition are both $57,590
    expect(screen.getAllByText('$57,590').length).toBe(2)
    expect(screen.getByText('$21,642')).toBeInTheDocument()
    expect(screen.getByText('4.0%')).toBeInTheDocument()
    expect(screen.getByText('94.0%')).toBeInTheDocument()
    expect(screen.getByText('99.0%')).toBeInTheDocument()
  })

  it('shows "Institution not found" when institution is null', () => {
    mockUseQuery.mockReturnValue([
      { fetching: false, data: { institution: null }, error: undefined },
      vi.fn(),
    ])
    renderDetail()
    expect(screen.getByText(/institution not found/i)).toBeInTheDocument()
  })

  it('pauses the query when unitID is null', () => {
    mockUseQuery.mockReturnValue([
      { fetching: false, data: undefined, error: undefined },
      vi.fn(),
    ])
    renderDetail({ unitID: null })
    expect(mockUseQuery).toHaveBeenCalledWith(
      expect.objectContaining({ pause: true }),
    )
  })

  it('renders dashes for null optional fields', () => {
    const partialInst = {
      ...MOCK_INSTITUTION,
      enrollment: null,
      admissionRate: null,
      inStateTuition: null,
      studentFacultyRatio: null,
    }
    mockUseQuery.mockReturnValue([
      { fetching: false, data: { institution: partialInst }, error: undefined },
      vi.fn(),
    ])
    renderDetail()
    // Should show dashes for null fields
    const dashes = screen.getAllByText('—')
    expect(dashes.length).toBeGreaterThanOrEqual(4)
  })
})

}

// Institution is the resolver for the institution field.
func (r *queryResolver) Institution(ctx context.Context, unitID string) (*model.InstitutionDetail, error) {
	sql := search.BuildInstitutionQuery()
	row := r.DB.QueryRow(ctx, sql, unitID)

	var inst model.InstitutionDetail
	if err := row.Scan(
		&inst.UnitID, &inst.Name, &inst.City, &inst.State,
		&inst.Latitude, &inst.Longitude,
		&inst.InstitutionType, &inst.Enrollment,
		&inst.GraduationRate, &inst.AdmissionRate,
		&inst.InStateTuition, &inst.OutOfStateTuition,
		&inst.AvgNetPrice, &inst.RetentionRate,
		&inst.StudentFacultyRatio,
	); err != nil {
		if errors.Is(err, pgx.ErrNoRows) {
			return nil, nil
		}
		slog.ErrorContext(ctx, "institution: query failed", "unit_id", unitID, "error", err)
		return nil, fmt.Errorf("institution: query: %w", err)
	}
	return &inst, nil
}

