package resolver

import (
	"fmt"
	"math"
	"strconv"

	"github.com/ketang/kapow/api/graph/model"
)

// ─────────────────────────────────────────────────────────────────────────────
// JSONB extraction helpers
// ─────────────────────────────────────────────────────────────────────────────

// jsonbObject returns a nested map from data[key], or nil if absent/wrong type.
func jsonbObject(data map[string]any, key string) map[string]any {
	v, ok := data[key]
	if !ok || v == nil {
		return nil
	}
	m, ok := v.(map[string]any)
	if !ok {
		return nil
	}
	return m
}

// jsonbString extracts a string value from data[key]. Returns nil if absent or
// not a string.
func jsonbString(data map[string]any, key string) *string {
	v, ok := data[key]
	if !ok || v == nil {
		return nil
	}
	switch s := v.(type) {
	case string:
		return &s
	default:
		str := fmt.Sprintf("%v", v)
		return &str
	}
}

// jsonbInt extracts an integer value from data[key]. Handles float64 (JSON
// default), string, and json.Number representations.
func jsonbInt(data map[string]any, key string) *int {
	v, ok := data[key]
	if !ok || v == nil {
		return nil
	}
	switch n := v.(type) {
	case float64:
		if math.IsNaN(n) || math.IsInf(n, 0) {
			return nil
		}
		i := int(n)
		return &i
	case string:
		i, err := strconv.Atoi(n)
		if err != nil {
			return nil
		}
		return &i
	default:
		return nil
	}
}

// jsonbFloat extracts a float64 value from data[key]. Handles float64, string,
// and integer representations.
func jsonbFloat(data map[string]any, key string) *float64 {
	v, ok := data[key]
	if !ok || v == nil {
		return nil
	}
	switch n := v.(type) {
	case float64:
		if math.IsNaN(n) || math.IsInf(n, 0) {
			return nil
		}
		return &n
	case string:
		f, err := strconv.ParseFloat(n, 64)
		if err != nil {
			return nil
		}
		return &f
	default:
		return nil
	}
}

// jsonbBool01 interprets data[key] as a boolean from "0"/"1" or 0/1.
func jsonbBool01(data map[string]any, key string) *bool {
	v, ok := data[key]
	if !ok || v == nil {
		return nil
	}
	switch n := v.(type) {
	case string:
		b := n == "1"
		return &b
	case float64:
		b := n == 1
		return &b
	default:
		return nil
	}
}

// jsonbStringSlice extracts a []string from data[key] where the value is a
// JSON array of strings.
func jsonbStringSlice(data map[string]any, key string) []string {
	v, ok := data[key]
	if !ok || v == nil {
		return nil
	}
	arr, ok := v.([]any)
	if !ok {
		return nil
	}
	out := make([]string, 0, len(arr))
	for _, elem := range arr {
		if s, ok := elem.(string); ok {
			out = append(out, s)
		}
	}
	if len(out) == 0 {
		return nil
	}
	return out
}

// ─────────────────────────────────────────────────────────────────────────────
// Per-theme extraction functions
// ─────────────────────────────────────────────────────────────────────────────

func extractLocation(data map[string]any) *model.InstitutionLocation {
	nces := jsonbObject(data, "nces")
	metro := jsonbObject(data, "metro_area")

	loc := &model.InstitutionLocation{}
	if nces != nil {
		loc.Locale = jsonbString(nces, "locale")
		loc.Region = jsonbString(nces, "region_id")
	}
	if metro != nil {
		loc.MetroArea = jsonbString(metro, "name")
		loc.MetroDistance = jsonbFloat(metro, "distance")
	}

	if loc.Locale == nil && loc.Region == nil && loc.MetroArea == nil && loc.MetroDistance == nil {
		return nil
	}
	return loc
}

func extractAcademics(data map[string]any) *model.InstitutionAcademics {
	nces := jsonbObject(data, "nces")
	if nces == nil {
		return nil
	}

	a := &model.InstitutionAcademics{
		InstitutionType:    jsonbString(nces, "ownership"),
		HighestDegree:      jsonbString(nces, "degrees_awarded_highest"),
		Enrollment:         jsonbInt(nces, "size"),
		GradEnrollment:     jsonbInt(nces, "grad_students"),
		StudentFacultyRatio: jsonbInt(nces, "demographics_student_faculty_ratio"),
		FullTimeFacultyRate: jsonbFloat(nces, "ft_faculty_rate"),
		Gender:             deriveGender(nces),
		OnlineOnly:         jsonbBool01(nces, "online_only"),
	}
	return a
}

// deriveGender returns "men-only", "women-only", or "coed" based on the
// nces.men_only and nces.women_only JSONB values.
func deriveGender(nces map[string]any) *string {
	menOnly := jsonbBool01(nces, "men_only")
	womenOnly := jsonbBool01(nces, "women_only")
	if menOnly != nil && *menOnly {
		s := "men-only"
		return &s
	}
	if womenOnly != nil && *womenOnly {
		s := "women-only"
		return &s
	}
	// If both are present and false, or if either is missing, default to coed.
	if menOnly != nil || womenOnly != nil {
		s := "coed"
		return &s
	}
	return nil
}

func extractCost(data map[string]any) *model.InstitutionCost {
	nces := jsonbObject(data, "nces")
	if nces == nil {
		return nil
	}

	c := &model.InstitutionCost{
		AvgNetPrice:          jsonbInt(nces, "avg_net_price"),
		TuitionInState:       jsonbInt(nces, "tuition_in_state"),
		TuitionOutOfState:    jsonbInt(nces, "tuition_out_of_state"),
		RoomAndBoard:         jsonbInt(nces, "roomboard_oncampus"),
		AvgNetPriceLowIncome: jsonbInt(nces, "net_price_by_income_level_0-30000"),
		PellGrantRate:        jsonbFloat(nces, "pell_grant_rate"),
		FederalLoanRate:      jsonbFloat(nces, "federal_loan_rate"),
		Endowment:            jsonbInt(nces, "endowment_end"),
	}
	return c
}

func extractOutcomes(data map[string]any) *model.InstitutionOutcomes {
	nces := jsonbObject(data, "nces")
	if nces == nil {
		return nil
	}

	o := &model.InstitutionOutcomes{
		AdmissionRate:  jsonbFloat(nces, "admission_rate_overall"),
		GraduationRate: jsonbFloat(nces, "completion_rate_4yr_150nt"),
		RetentionRate:  jsonbFloat(nces, "retention_rate_four_year_full_time_pooled"),
		TransferRate:   jsonbFloat(nces, "transfer_rate_4yr_full_time_pooled"),
	}
	return o
}

func extractRankings(data map[string]any) *model.InstitutionRankings {
	r := &model.InstitutionRankings{}

	if obj := jsonbObject(data, "us_news____national_universities"); obj != nil {
		r.UsNewsNational = rankValue(obj)
	}
	if obj := jsonbObject(data, "us_news____liberal_arts_colleges"); obj != nil {
		r.UsNewsLiberalArts = rankValue(obj)
	}
	if obj := jsonbObject(data, "forbes_____"); obj != nil {
		r.Forbes = rankValue(obj)
	}
	if obj := jsonbObject(data, "washington_monthly____national_universities"); obj != nil {
		r.WashingtonMonthlyNational = rankValue(obj)
	}
	if obj := jsonbObject(data, "washington_monthly____liberal_arts"); obj != nil {
		r.WashingtonMonthlyLiberalArts = rankValue(obj)
	}
	if obj := jsonbObject(data, "niche____best_colleges"); obj != nil {
		r.Niche = rankValue(obj)
	}
	if obj := jsonbObject(data, "money_com_____"); obj != nil {
		r.MoneyScore = jsonbFloat(obj, "score")
	}

	if r.UsNewsNational == nil && r.UsNewsLiberalArts == nil && r.Forbes == nil &&
		r.WashingtonMonthlyNational == nil && r.WashingtonMonthlyLiberalArts == nil &&
		r.Niche == nil && r.MoneyScore == nil {
		return nil
	}
	return r
}

// rankValue extracts the rank integer from a ranking object, only if method == "rank".
func rankValue(obj map[string]any) *int {
	method := jsonbString(obj, "method")
	if method == nil || *method != "rank" {
		return nil
	}
	return jsonbInt(obj, "rank")
}

func extractAdmissions(data map[string]any) *model.InstitutionAdmissions {
	platforms := jsonbStringSlice(data, "applications")
	if platforms == nil {
		return nil
	}
	return &model.InstitutionAdmissions{
		ApplicationPlatforms: platforms,
	}
}

func extractAthletics(data map[string]any) *model.InstitutionAthletics {
	ncaa := jsonbObject(data, "ncaa")
	if ncaa == nil {
		return nil
	}

	a := &model.InstitutionAthletics{
		NcaaDivision:   jsonbString(ncaa, "division"),
		NcaaConference: jsonbString(ncaa, "conference"),
	}
	if a.NcaaDivision == nil && a.NcaaConference == nil {
		return nil
	}
	return a
}

func extractClimate(data map[string]any) *model.InstitutionClimate {
	koppen := jsonbObject(data, "koppen")
	if koppen == nil {
		return nil
	}

	c := &model.InstitutionClimate{
		KoppenClimate:       jsonbString(koppen, "climate"),
		KoppenTemperature:   jsonbString(koppen, "temperature"),
		KoppenPrecipitation: jsonbString(koppen, "precipitation"),
	}
	if c.KoppenClimate == nil && c.KoppenTemperature == nil && c.KoppenPrecipitation == nil {
		return nil
	}
	return c
}

func extractCulture(data map[string]any) *model.InstitutionCulture {
	partisan := jsonbObject(data, "partisan_lean_538")
	if partisan == nil {
