	}

	c := &model.InstitutionCulture{
		PartisanDirection: jsonbString(partisan, "direction"),
		PartisanScore:     jsonbFloat(partisan, "score"),
	}
	if c.PartisanDirection == nil && c.PartisanScore == nil {
		return nil
	}
	return c
