 93→// jsonbBool01 interprets data[key] as a boolean from "0"/"1" or 0/1.
 94→func jsonbBool01(data map[string]any, key string) *bool {
 95→	v, ok := data[key]
 96→	if !ok || v == nil {
 97→		return nil
 98→	}
 99→	switch n := v.(type) {
100→	case string:
101→		b := n == "1"
102→		return &b
103→	case float64:
104→		b := n == 1
105→		return &b
106→	default:
107→		return nil
108→	}
109→}
