111→// jsonbStringSlice extracts a []string from data[key] where the value is a
112→// JSON array of strings.
113→func jsonbStringSlice(data map[string]any, key string) []string {
114→	v, ok := data[key]
115→	if !ok || v == nil {
116→		return nil
117→	}
118→	arr, ok := v.([]any)
119→	if !ok {
120→		return nil
121→	}
122→	out := make([]string, 0, len(arr))
123→	for _, elem := range arr {
124→		if s, ok := elem.(string); ok {
125→			out = append(out, s)
126→		}
127→	}
128→	if len(out) == 0 {
129→		return nil
130→	}
131→	return out
132→}
