package resolver

import (
	"fmt"
	"math"
	"strconv"

	"github.com/ketang/kapow/api/graph/model"
)

// ─────────────────────────────────────────────────────────────────────────────
// JSONB extraction helpers
// ─────────────────────────────────────────────────────────────────────────────

// jsonbObject returns a nested map from data[key], or nil if absent/wrong type.
func jsonbObject(data map[string]any, key string) map[string]any {
	v, ok := data[key]
	if !ok || v == nil {
		return nil
	}
	m, ok := v.(map[string]any)
	if !ok {
		return nil
	}
	return m
}

// jsonbString extracts a string value from data[key]. Returns nil if absent or
// not a string.
func jsonbString(data map[string]any, key string) *string {
	v, ok := data[key]
	if !ok || v == nil {
		return nil
	}
	switch s := v.(type) {
	case string:
		return &s
	default:
		str := fmt.Sprintf("%v", v)
		return &str
	}
}

// jsonbInt extracts an integer value from data[key]. Handles float64 (JSON
// default), string, and json.Number representations.
func jsonbInt(data map[string]any, key string) *int {
	v, ok := data[key]
	if !ok || v == nil {
		return nil
	}
	switch n := v.(type) {
	case float64:
		if math.IsNaN(n) || math.IsInf(n, 0) {
			return nil
		}
		i := int(n)
		return &i
	case string:
		i, err := strconv.Atoi(n)
		if err != nil {
			return nil
		}
		return &i
	default:
		return nil
	}
}

// jsonbFloat extracts a float64 value from data[key]. Handles float64, string,
// and integer representations.
func jsonbFloat(data map[string]any, key string) *float64 {
	v, ok := data[key]
	if !ok || v == nil {
		return nil
	}
	switch n := v.(type) {
	case float64:
		if math.IsNaN(n) || math.IsInf(n, 0) {
			return nil
		}
		return &n
	case string:
		f, err := strconv.ParseFloat(n, 64)
		if err != nil {
			return nil
		}
		return &f
	default:
		return nil
	}
}

// jsonbBool01 interprets data[key] as a boolean from "0"/"1" or 0/1.
func jsonbBool01(data map[string]any, key string) *bool {
	v, ok := data[key]
	if !ok || v == nil {
		return nil
	}
	switch n := v.(type) {
	case string:
		b := n == "1"
		return &b
