// deriveGender returns "men-only", "women-only", or "coed" based on the
// nces.men_only and nces.women_only JSONB values.
func deriveGender(nces map[string]any) *string {
	menOnly := jsonbBool01(nces, "men_only")
	womenOnly := jsonbBool01(nces, "women_only")
	if menOnly != nil && *menOnly {
		s := "men-only"
		return &s
	}
	if womenOnly != nil && *womenOnly {
		s := "women-only"
		return &s
	}
