import { Button as MantineButton, type ButtonProps as MantineButtonProps } from '@mantine/core'
import { forwardRef } from 'react'

type Variant = 'default' | 'accent' | 'outline' | 'accent-outline' | 'ghost' | 'link'
type Size = 'default' | 'sm' | 'lg' | 'xl' | 'icon'

export interface ButtonProps
  extends Omit<React.ButtonHTMLAttributes<HTMLButtonElement>, 'color'> {
  variant?: Variant
  size?: Size
  asChild?: boolean
}

const variantMap: Record<Variant, Pick<MantineButtonProps, 'variant' | 'color'>> = {
  default: { variant: 'filled', color: 'brand' },
  accent: { variant: 'filled', color: 'accent' },
  outline: { variant: 'outline', color: 'brand' },
  'accent-outline': { variant: 'outline', color: 'accent' },
  ghost: { variant: 'subtle', color: 'brand' },
  link: { variant: 'transparent', color: 'brand' },
}

const sizeMap: Record<Size, MantineButtonProps['size']> = {
  default: 'md',
  sm: 'sm',
  lg: 'lg',
  xl: 'xl',
  icon: 'md',
}

const Button = forwardRef<HTMLButtonElement, ButtonProps>(
  // eslint-disable-next-line @typescript-eslint/no-unused-vars
  ({ variant = 'default', size = 'default', className, asChild: _asChild, ...props }, ref) => {
    const mapped = variantMap[variant]
    return (
      <MantineButton
        ref={ref}
        variant={mapped.variant}
        color={mapped.color}
        size={sizeMap[size]}
        className={className}
        {...props}
      />
    )
  },
)
Button.displayName = 'Button'

export { Button }

