  '31': 'Town: Fringe',
  '32': 'Town: Distant',
  '33': 'Town: Remote',
  '41': 'Rural: Fringe',
  '42': 'Rural: Distant',
  '43': 'Rural: Remote',
}

const REGION_LABELS: Record<string, string> = {
  '0': 'U.S. Service Schools',
