)

// ─────────────────────────────────────────────────────────────────────────────
// Helpers
// ─────────────────────────────────────────────────────────────────────────────

func newTestQueryResolver(q db.Querier) *queryResolver {
	return &queryResolver{
		Resolver: &Resolver{
			DB:     q,
			Search: search.NewRegistry(),
		},
	}
}

func mustJSON(v any) json.RawMessage {
	b, err := json.Marshal(v)
	if err != nil {
		panic(err)
	}
	return b
}

func ptrInt(n int) *int { return &n }

func ptrFloat64(f float64) *float64 { return &f }

func ptrString(s string) *string { return &s }

// 10-column row helper matching the always-10-column SELECT.
var mockCols = []string{
	"unit_id", "institution_name", "city", "state",
	"latitude", "longitude", "distance", "my_price", "data", "blend_score",
}

// ─────────────────────────────────────────────────────────────────────────────
// Unit tests — no DB required; error is returned before any DB call
// ─────────────────────────────────────────────────────────────────────────────

func TestSearch_UnknownField(t *testing.T) {
	t.Parallel()
	r := newTestQueryResolver(nil) // DB is nil — must not be reached
	_, err := r.Search(context.Background(), []*model.FilterInput{
		{Field: search.SearchFieldName("not_a_real_field"), Value: mustJSON("value")},
	}, nil, nil, nil, nil, nil)
	if err == nil {
		t.Fatal("expected error for unknown filter field, got nil")
	}
	if !strings.Contains(err.Error(), "not_a_real_field") {
		t.Errorf("expected field name in error message, got: %v", err)
	}
}

// ─────────────────────────────────────────────────────────────────────────────
// Mock-based unit tests — pgxmock replaces the real database
// ─────────────────────────────────────────────────────────────────────────────

func TestSearch_NoFilters_MockDB(t *testing.T) {
	t.Parallel()
	mock, err := pgxmock.NewPool()
	if err != nil {
		t.Fatalf("pgxmock.NewPool: %v", err)
	}
	defer mock.Close()

	lat := 42.0
	lng := -71.0

	// Count query
	mock.ExpectQuery("SELECT COUNT").
		WillReturnRows(pgxmock.NewRows([]string{"count"}).AddRow(3))

	// Rows query — now 8 columns; use pgxmock.AnyArg for pagination params
	mock.ExpectQuery("SELECT unit_id").
		WithArgs(pgxmock.AnyArg(), pgxmock.AnyArg()).
		WillReturnRows(pgxmock.NewRows(mockCols).
			AddRow("100001", "University A", "Boston", "MA", &lat, &lng, nil, nil, nil, nil).
			AddRow("100002", "University B", "Cambridge", "MA", &lat, &lng, nil, nil, nil, nil).
			AddRow("100003", "College C", "Somerville", "MA", &lat, &lng, nil, nil, nil, nil))

	r := newTestQueryResolver(mock)
	resp, err := r.Search(context.Background(), nil, nil, nil, nil, nil, nil)
	if err != nil {
		t.Fatalf("Search: %v", err)
	}
	if resp.Total != 3 {
		t.Errorf("Total = %d, want 3", resp.Total)
	}
	if len(resp.Results) != 3 {
		t.Errorf("len(Results) = %d, want 3", len(resp.Results))
	}
	if resp.Limit != search.DefaultLimit {
		t.Errorf("Limit = %d, want %d", resp.Limit, search.DefaultLimit)
	}
	if resp.Offset != 0 {
		t.Errorf("Offset = %d, want 0", resp.Offset)
	}

	// Check first result
	if resp.Results[0].UnitID != "100001" {
		t.Errorf("Results[0].UnitID = %q, want %q", resp.Results[0].UnitID, "100001")
	}

	if err := mock.ExpectationsWereMet(); err != nil {
		t.Errorf("unmet expectations: %v", err)
	}
}

