			t.Errorf("UnitID %q appears in both page 0 and page 1", r.UnitID)
		}
	}
}

func TestIntegrationSearch_UnknownField(t *testing.T) {
	pool := integrationDB(t)
	r := newTestQueryResolver(pool)

	_, err := r.Search(context.Background(), []*model.FilterInput{
		{Field: search.SearchFieldName("not_a_field"), Value: mustJSON("x")},
	}, nil, nil, nil, nil, nil)
	if err == nil {
		t.Fatal("expected error for unknown field")
	}
}

func TestIntegrationSearch_InstitutionByUnitID(t *testing.T) {
	pool := integrationDB(t)
	r := newTestQueryResolver(pool)

	// First get a valid unit_id from a search result.
	resp, err := r.Search(context.Background(), nil, ptrInt(1), nil, nil, nil, nil)
	if err != nil {
		t.Fatalf("Search: %v", err)
	}
	if len(resp.Results) == 0 {
		t.Skip("no data to test institution detail")
	}

	unitID := resp.Results[0].UnitID
	inst, err := r.Institution(context.Background(), unitID)
	if err != nil {
		t.Fatalf("Institution(%q): %v", unitID, err)
	}
	if inst == nil {
		t.Fatalf("Institution(%q) returned nil", unitID)
	}
	if inst.UnitID != unitID {
		t.Errorf("UnitID = %q, want %q", inst.UnitID, unitID)
	}
	if inst.Name == "" {
		t.Error("expected non-empty Name")
	}

	// Non-existent unit_id should return nil.
	inst, err = r.Institution(context.Background(), "000000")
	if err != nil {
		t.Fatalf("Institution(000000): %v", err)
	}
	if inst != nil {
		t.Errorf("expected nil for non-existent unit_id, got %+v", inst)
	}
}

